const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const FIRST_INSURANCE_SURCHARGE = 1.1;
const PROCESSING_FEE = 5;

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);

const quotePremium = (items: Item[]): number =>
  sumBasePremiums(items) * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;

export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
  results: input.steps.map((step) => ({ premium: quotePremium(step.items) })),
});

