const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const PROCESSING_FEE = 5;

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);

const applyFirstInsuranceSurcharge = (amount: number): number =>
  (amount * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100;

const quotePremium = (items: Item[]): number =>
  applyFirstInsuranceSurcharge(sumBasePremiums(items)) + PROCESSING_FEE;
